@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@{
    // Shared inner content so the <button> and <a> render paths stay identical.
    RenderFragment inner = @<text>
        @if (IsLoading)
        {
            <Spinner Class="h-4 w-4" />
            @if (LoadingText != null)
            {
                <span>@LoadingText</span>
            }
            else
            {
                @ChildContent
            }
            @if (RightIcon != null)
            {
                @RightIcon
            }
        }
        else
        {
            @if (LeftIcon != null)
            {
                @LeftIcon
            }
            @ChildContent
            @if (RightIcon != null)
            {
                @RightIcon
            }
        }
    </text>;
}
@if (Href is not null)
{
    @* Link-button (#269): polymorphic render as <a> for the common "link styled
       as a button" case. <a> can't be natively disabled, so a disabled/loading
       link gets aria-disabled + pointer-events-none/opacity directly (the
       `disabled:` utility variant only targets a real :disabled element). *@
    <a @ref="_el" href="@Href" id="@Slot?.Id" class="@LinkCssClass"
       aria-disabled="@((IsLoading || Disabled) ? "true" : null)"
       tabindex="@((IsLoading || Disabled) ? "-1" : null)"
       @attributes="MergedAttributes" @onclick="HandleClick"
       @onclick:stopPropagation="StopPropagation" @onclick:preventDefault="PreventDefault">@inner</a>
}
else
{
    <button @ref="_el" type="@TypeAttr" id="@Slot?.Id" class="@CssClass" disabled="@(IsLoading || Disabled)" @attributes="MergedAttributes" @onclick="HandleClick" @onclick:stopPropagation="StopPropagation" @onclick:preventDefault="PreventDefault">@inner</button>
}

@code {
    /// <summary>The button's label content. Hidden in favor of <see cref="LoadingText"/> while <see cref="IsLoading"/> is true (unless <see cref="LoadingText"/> is null).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Icon rendered before <see cref="ChildContent"/>. Hidden while <see cref="IsLoading"/> is true (replaced by the spinner).</summary>
    [Parameter] public RenderFragment? LeftIcon { get; set; }

    /// <summary>Icon rendered after <see cref="ChildContent"/>. Still shown while <see cref="IsLoading"/> is true.</summary>
    [Parameter] public RenderFragment? RightIcon { get; set; }

    /// <summary>Visual style. Defaults to <see cref="ButtonVariant.Default"/> (solid primary color).</summary>
    [Parameter] public ButtonVariant Variant { get; set; } = ButtonVariant.Default;

    /// <summary>Button height/padding. Defaults to <see cref="ButtonSize.Default"/>. Combines with <see cref="Density"/> to pick the final height.</summary>
    [Parameter] public ButtonSize Size { get; set; } = ButtonSize.Default;
    /// <summary>Per-button density override. When null, the button inherits
    /// from any ancestor <see cref="DensityScope"/>; if neither is set,
    /// behaviour matches the historical <c>Comfortable</c> default. Only
    /// padding / row-height shifts between values — text size + radius
    /// are governed by <see cref="Size"/>.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    /// <summary>When true, the button stretches to fill its container's width (<c>w-full</c>). Default is <c>false</c>.</summary>
    [Parameter] public bool FullWidth { get; set; }

    /// <summary>Additional CSS classes merged onto the root button/anchor element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Invoked on click, after any cascaded trigger's own activation (Popover/Dropdown/Dialog AsChild) has run.</summary>
    [Parameter] public EventCallback<Microsoft.AspNetCore.Components.Web.MouseEventArgs> OnClick { get; set; }

    /// <summary>Disables the button. On the <c>&lt;a&gt;</c> render path (see <see cref="Href"/>) this maps to <c>aria-disabled</c> plus non-interactive styling instead of a native <c>disabled</c> attribute.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>When true, shows a spinner in place of <see cref="LeftIcon"/> and disables interaction (<c>pointer-events-none</c>), without visually dimming like <see cref="Disabled"/>.</summary>
    [Parameter] public bool IsLoading { get; set; }

    /// <summary>Text shown next to the spinner while <see cref="IsLoading"/> is true. When null, <see cref="ChildContent"/> stays visible alongside the spinner instead.</summary>
    [Parameter] public string? LoadingText { get; set; }

    /// <summary>
    /// When set, the button renders as an <c>&lt;a href&gt;</c> styled exactly like
    /// a button — the Blazor-idiomatic polymorphism for the common "link that
    /// looks like a button" case (#269). All visual props (Variant/Size/icons)
    /// still apply; <see cref="Disabled"/>/<see cref="IsLoading"/> map to
    /// <c>aria-disabled</c> + non-interactive styling since a link can't be
    /// natively disabled. Leave null for a normal <c>&lt;button&gt;</c>.
    /// </summary>
    [Parameter] public string? Href { get; set; }

    /// <summary>HTML button type. Defaults to <see cref="ButtonType.Button"/>
    /// — explicitly NOT submit. The HTML spec says &lt;button&gt; inside
    /// &lt;form&gt; defaults to <c>type="submit"</c>, which would submit the
    /// form on every click. Lumeo defaults to a regular button so Buttons
    /// don't silently submit EditForm; opt in via <c>Type="Submit"</c>.</summary>
    [Parameter] public ButtonType Type { get; set; } = ButtonType.Button;

    /// <summary>Stop click propagation to ancestors. Use this instead of
    /// the Razor directive <c>@@onclick:stopPropagation</c> on a Lumeo
    /// component — that directive creates an <c>onclick</c> parameter
    /// that case-insensitively collides with the <c>OnClick</c>
    /// parameter, producing a compile error. The directive only works
    /// natively on HTML elements; this parameter is the equivalent for
    /// the &lt;button&gt; element underneath.</summary>
    [Parameter] public bool StopPropagation { get; set; }

    /// <summary>Prevent the default click action on the underlying
    /// &lt;button&gt; element. Same rationale as <see cref="StopPropagation"/>
    /// — Razor's <c>@@onclick:preventDefault</c> directive collides
    /// case-insensitively with the <c>OnClick</c> parameter on
    /// components.</summary>
    [Parameter] public bool PreventDefault { get; set; }

    /// <summary>
    /// Visual feedback when the button is pressed down. Default is <see cref="ButtonPressEffect.None"/>
    /// (no press animation — original behaviour).
    /// </summary>
    [Parameter] public ButtonPressEffect PressEffect { get; set; } = ButtonPressEffect.None;

    /// <summary>Unmatched attributes are splatted onto the root button/anchor element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // When this Button is the child of a trigger rendered AsChild (Popover/Dropdown/
    // Dialog/...), the trigger cascades a TriggerSlot the Button auto-applies, so the
    // pair renders as ONE <button> instead of a nested role=button wrapper. Null in
    // every normal usage — all the Slot?.* below are then no-ops, so behaviour is
    // byte-identical when no trigger is involved.
    [CascadingParameter] private TriggerSlot? Slot { get; set; }

    private Microsoft.AspNetCore.Components.ElementReference _el;

    private string CssClass => Cx.Merge(
        Slot?.Class,                 // trigger base classes first, so the Button's own classes win conflicts
        VariantClasses,
        SizeClasses,
        BaseClasses,
        PressEffectClass,
        "cursor-pointer disabled:cursor-not-allowed",
        Cx.When(IsLoading, "pointer-events-none opacity-70"),
        Cx.When(FullWidth, "w-full"),
        Class);

    // Slot a11y/state attrs first, then the consumer's unmatched attributes so an
    // author-set aria-*/data-* on the Button overrides the slot. Falls through to the
    // plain AdditionalAttributes (possibly null) when no slot is cascaded.
    private IReadOnlyDictionary<string, object>? MergedAttributes
    {
        get
        {
            if (Slot is null) return AdditionalAttributes;
            var d = new Dictionary<string, object>(Slot.Attributes);
            // Forward the slot's hover/focus handlers (HoverCard / Tooltip triggers)
            // so a Button rendered AsChild folds them onto the real <button>. Only
            // present when the slot supplies them — click-toggle triggers leave these
            // default, so a plain Button is byte-identical. Click is composed in
            // HandleClick; keydown stays native (Enter/Space already fire click).
            if (Slot.OnMouseEnter.HasDelegate) d["onmouseenter"] = Slot.OnMouseEnter;
            if (Slot.OnMouseLeave.HasDelegate) d["onmouseleave"] = Slot.OnMouseLeave;
            if (Slot.OnFocusIn.HasDelegate) d["onfocusin"] = Slot.OnFocusIn;
            if (Slot.OnFocusOut.HasDelegate) d["onfocusout"] = Slot.OnFocusOut;
            if (AdditionalAttributes is not null)
                foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value;
            return d;
        }
    }

    // Compose the trigger's activation (open/toggle) BEFORE the consumer's own OnClick,
    // so the overlay always opens even if the consumer handler stops propagation. No-op
    // slot hop when not AsChild. A native <button> fires this on Enter/Space too, so the
    // slot's keyboard callback is intentionally NOT wired here (it would double-activate).
    private async Task HandleClick(Microsoft.AspNetCore.Components.Web.MouseEventArgs e)
    {
        if (Slot is not null) await Slot.OnClick.InvokeAsync(e);
        await OnClick.InvokeAsync(e);
    }

    // Link variant can't use the `disabled:` utilities (no :disabled state on
    // <a>), so fold the inactive styling in directly.
    private string LinkCssClass => Cx.Merge(CssClass, Cx.When(IsLoading || Disabled, "pointer-events-none opacity-50"));

    private const string BaseClasses = "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

    private string? PressEffectClass => PressEffect switch
    {
        ButtonPressEffect.Scale => "lumeo-press-scale",
        ButtonPressEffect.Brightness => "lumeo-press-brightness",
        ButtonPressEffect.Ripple => "lumeo-press-ripple",
        _ => null
    };

    private string VariantClasses => Variant switch
    {
        ButtonVariant.Default => "bg-primary text-primary-foreground shadow hover:bg-primary/90",
        ButtonVariant.Destructive => "bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90",
        ButtonVariant.Outline => "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        ButtonVariant.Secondary => "bg-secondary text-secondary-foreground shadow-sm hover:bg-secondary/80",
        ButtonVariant.Ghost => "hover:bg-accent hover:text-accent-foreground",
        ButtonVariant.Link => "text-primary underline-offset-4 hover:underline",
        _ => ""
    };

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    private string SizeClasses
    {
        get
        {
            var (height, pad, padIcon) = (Size, EffectiveDensity) switch
            {
                (ButtonSize.Sm, Lumeo.Density.Compact)    => ("h-7",  "px-2.5",  "h-7 w-7"),
                (ButtonSize.Sm, Lumeo.Density.Spacious)   => ("h-9",  "px-4",    "h-9 w-9"),
                (ButtonSize.Sm, _)                        => ("h-8",  "px-3",    "h-8 w-8"),
                (ButtonSize.Lg, Lumeo.Density.Compact)    => ("h-9",  "px-6",    "h-9 w-9"),
                (ButtonSize.Lg, Lumeo.Density.Spacious)   => ("h-12", "px-10",   "h-12 w-12"),
                (ButtonSize.Lg, _)                        => ("h-10", "px-8",    "h-10 w-10"),
                (ButtonSize.Default, Lumeo.Density.Compact)  => ("h-8",  "px-3",  "h-8 w-8"),
                (ButtonSize.Default, Lumeo.Density.Spacious) => ("h-11", "px-6 py-2.5", "h-11 w-11"),
                (ButtonSize.Default, _)                      => ("h-9",  "px-4 py-2",   "h-9 w-9"),
                (ButtonSize.Icon, Lumeo.Density.Compact)  => ("h-8",  "",       "h-8 w-8"),
                (ButtonSize.Icon, Lumeo.Density.Spacious) => ("h-11", "",       "h-11 w-11"),
                (ButtonSize.Icon, _)                      => ("h-9",  "",       "h-9 w-9"),
                _ => ("", "", "")
            };
            var textClass = Size == ButtonSize.Sm ? " text-xs" : "";
            var radiusClass = Size is ButtonSize.Sm or ButtonSize.Lg ? " rounded-md" : "";
            return Size == ButtonSize.Icon
                ? padIcon + radiusClass
                : $"{height} {pad}{textClass}{radiusClass}";
        }
    }

    // Whether the JS pointerdown ripple listener is currently bound to _el.
    // Tracked so the attach/detach is reconciled against the live PressEffect on
    // EVERY render — not latched on firstRender — and torn down on dispose.
    private bool _rippleAttached;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Reconcile the ripple listener with the current PressEffect, not just the
        // first-render value: a runtime None->Ripple flip must now attach, and a
        // Ripple->None flip must detach the leaked listener (triage #145, subsumes
        // the missing-dispose leak of #22).
        if (PressEffect == ButtonPressEffect.Ripple && !_rippleAttached)
        {
            try
            {
                await Interop.RippleAttachAsync(_el);
                _rippleAttached = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
        else if (PressEffect != ButtonPressEffect.Ripple && _rippleAttached)
        {
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _rippleAttached = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_rippleAttached)
        {
            try
            {
                await Interop.RippleDetachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _rippleAttached = false;
        }
    }

    public enum ButtonVariant { Default, Destructive, Outline, Secondary, Ghost, Link }
    public enum ButtonSize { Default, Sm, Lg, Icon }
    public enum ButtonType { Button, Submit, Reset }

    private string TypeAttr => Type switch
    {
        ButtonType.Submit => "submit",
        ButtonType.Reset => "reset",
        _ => "button",
    };

    /// <summary>Visual press feedback style for <see cref="Button"/>.</summary>
    public enum ButtonPressEffect
    {
        /// <summary>No press animation (default).</summary>
        None,
        /// <summary>Button slightly scales down (~97%) while pressed.</summary>
        Scale,
        /// <summary>Button darkens/brightens slightly while pressed.</summary>
        Brightness,
        /// <summary>Click ripples outward from the cursor point (JS-interop, uses CSS mask).</summary>
        Ripple
    }
}
